    public void completed(WorkflowEventArgs _workflowEventArgs)
    {
        next completed(_workflowEventArgs);

        RecId vendBankAccountRecId  = _workflowEventArgs.parmWorkflowContext().parmRecId();
        VendBankAccount bankAccount = VendBankAccount::findByRecId(vendBankAccountRecId,true);
        VendTable vendTable         = VendTable::find(bankAccount.VendAccount,true);
        
        UBSVendBankAccountAccountIdOrigField UBSVendBankAccountAccountIdOrigField = UBSVendBankAccountAccountIdOrigField::
                                                                                                findVendAccountTableAccountId(bankAccount.AccountID);
        int64 vendBankAccountCount = VendBankAccount::vendBankAccountPerVendorCount(vendTable.AccountNum);

        if(UBSVendBankAccountAccountIdOrigField && vendBankAccountCount == 1)
        {
            str   orignator         = WorkflowTrackingStatusTable::findByCorrelation(
                                                _workflowEventArgs.parmWorkflowContext().parmWorkflowCorrelationId()).Originator;

            ttsbegin;
            vendTable.BankAccount = bankAccount.AccountID;
            vendTable.update();
            ttscommit;
             
            ttsbegin;
            VendTableChangeProposal change = VendTableChangeProposal::findOrCreate(vendTable.RecId, true);
            change.BankAccount = bankAccount.AccountID;
            change.setFlagForChangedField(VendTableChangeProposalField::BankAccount);
            change.update();
            ttscommit;

            ttsbegin;
            VendTable::updateWorkflowState(vendTable.RecId, VendTableChangeProposalWorkflowState::Submitted);
            WorkflowCorrelationId   workflowCorrelationId = Workflow::activateFromWorkflowType(workFlowTypeStr(VendTableChangeProposalWorkflow),
                                                                               vendTable.RecId,
                                                                               '@UBS:UBSAutomacticSubmission',
                                                                               false,
                                                                               orignator);

            UBSVendBankAccountAccountIdOrigField.selectForUpdate(true);
            UBSVendBankAccountAccountIdOrigField.delete();
            ttscommit;
        }
    }
